<?php
namespace Tests\Unit;
use App\Services\Trading\PositionManagementPolicyService;
use Tests\TestCase;
class PositionManagementPolicyServiceTest extends TestCase
{protected function state(array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_position_state_v1','status'=>'condition_observed','position_id'=>'position-bumi-1','ticker'=>'BUMI','position_side'=>'long','protection_checks'=>['stop_reference_available'=>true,'stop_reference_breached'=>true,'target_reference_available'=>true,'target_reference_reached'=>false],'reason_codes'=>['POSITION_STOP_REFERENCE_BREACHED']],$over);}protected function policy(array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_position_management_policy_v1','status'=>'reference_only','policy_id'=>'policy-1','policy_version'=>'management_reference_policy_v1','position_id'=>'position-bumi-1','ticker'=>'BUMI','supported_side'=>'long','rules'=>[['rule_id'=>'review-stop-breach','condition'=>'stop_reference_breached','candidate_type'=>'protection_breach_review','priority'=>100,'enabled'=>true],['rule_id'=>'review-target-reach','condition'=>'target_reference_reached','candidate_type'=>'target_reached_review','priority'=>90,'enabled'=>true]],'source'=>['type'=>'synthetic_test_fixture','identifier'=>'policy'],'approved_for_selection'=>false,'approved_for_execution'=>false,'synthetic_test_only'=>true],$over);}public function test_policy_unavailable_and_no_condition():void{$svc=new PositionManagementPolicyService();$r=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'position_management_policy'=>null]);$this->assertSame('unavailable',$r['status']);$n=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(['status'=>'monitoring_reference','protection_checks'=>['stop_reference_available'=>true,'stop_reference_breached'=>false,'target_reference_available'=>true,'target_reference_reached'=>false],'reason_codes'=>[]]),'position_management_policy'=>$this->policy()]);$this->assertSame('no_condition',$n['status']);$this->assertContains('POSITION_MANAGEMENT_NO_IMPLICIT_HOLD',$n['warnings']);}
public function test_invalid_policy_rules_are_rejected():void{$svc=new PositionManagementPolicyService();foreach([['rules'=>[['rule_id'=>'x','condition'=>'bad','candidate_type'=>'protection_breach_review','priority'=>1,'enabled'=>true]]],['rules'=>[['rule_id'=>'x','condition'=>'stop_reference_breached','candidate_type'=>'SELL','priority'=>1,'enabled'=>true]]],['rules'=>[['rule_id'=>'x','condition'=>'stop_reference_breached','candidate_type'=>'protection_breach_review','priority'=>1,'enabled'=>true],['rule_id'=>'x','condition'=>'target_reference_reached','candidate_type'=>'target_reached_review','priority'=>2,'enabled'=>true]]],['approved_for_selection'=>true]] as $over){$this->expectException(\InvalidArgumentException::class);$svc->validatePolicy($this->policy($over));break;}}
public function test_identity_mismatch_and_no_matching_rule():void{$svc=new PositionManagementPolicyService();$m=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'position_management_policy'=>$this->policy(['ticker'=>'DEWA'])]);$this->assertSame('blocked',$m['status']);$n=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'position_management_policy'=>$this->policy(['rules'=>[['rule_id'=>'review-target','condition'=>'target_reference_reached','candidate_type'=>'target_reached_review','priority'=>1,'enabled'=>true]]])]);$this->assertSame('no_matching_rule',$n['status']);}
public function test_stop_target_missing_and_priority():void{$svc=new PositionManagementPolicyService();$s=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'position_management_policy'=>$this->policy()]);$this->assertSame('matched_reference_rule',$s['status']);$this->assertSame('protection_breach_review',$s['candidate_type']);$t=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(['protection_checks'=>['stop_reference_available'=>true,'stop_reference_breached'=>false,'target_reference_available'=>true,'target_reference_reached'=>true],'reason_codes'=>['POSITION_TARGET_REFERENCE_REACHED']]),'position_management_policy'=>$this->policy()]);$this->assertSame('target_reached_review',$t['candidate_type']);$missing=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(['status'=>'partial','protection_checks'=>['stop_reference_available'=>false,'stop_reference_breached'=>null,'target_reference_available'=>true,'target_reference_reached'=>false],'reason_codes'=>['POSITION_PROTECTION_REFERENCE_UNAVAILABLE']]),'position_management_policy'=>$this->policy(['rules'=>[['rule_id'=>'review-missing','condition'=>'protection_reference_missing','candidate_type'=>'protection_missing_review','priority'=>5,'enabled'=>true]]])]);$this->assertSame('protection_missing_review',$missing['candidate_type']);$tie=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'position_management_policy'=>$this->policy(['rules'=>[['rule_id'=>'a','condition'=>'stop_reference_breached','candidate_type'=>'protection_breach_review','priority'=>1,'enabled'=>true],['rule_id'=>'b','condition'=>'stop_reference_breached','candidate_type'=>'protection_breach_review','priority'=>1,'enabled'=>true]]])]);$this->assertSame('invalid',$tie['status']);}
public function test_deterministic_output_and_schema():void{$svc=new PositionManagementPolicyService();$a=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'position_management_policy'=>$this->policy()]);$b=$svc->evaluate(['decision_scope'=>'position_management','position_state'=>$this->state(),'position_management_policy'=>$this->policy()]);$this->assertSame($a,$b);$this->assertSame('trading_position_management_policy_evaluation_v1',$a['schema_version']);}}
